#!/usr/bin/env python3
"""
solution.py

Reads numbers.txt and prints the count of even integers.
"""

def main():
    try:
        with open("numbers.txt", "r") as f:
            lines = f.readlines()
    except FileNotFoundError:
        print("numbers.txt not found.")
        return

    even_count = 0
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        try:
            num = int(stripped)
            if num % 2 == 0:
                even_count += 1
        except ValueError:
            # Skip lines that are not valid integers
            continue

    print(even_count)

if __name__ == "__main__":
    main()

