def main():
    # Define building coordinates
    buildings = [(5, 2), (2, 2)]

    # Check bounds and uniqueness
    seen = set()
    for x, y in buildings:
        if not (0 <= x <= 6 and 0 <= y <= 6):
            print("INVALID")
            return
        if (x, y) in seen:
            print("INVALID")
            return
        seen.add((x, y))

    print("VALID")

